import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "🌧️", high: 24, low: 19 },
    { day: "Thu", icon: "☁️", high: 25, low: 18 },
    { day: "Fri", icon: "☀️", high: 29, low: 21 }
  ]
}: Props) {
  const displayUnit = unit ?? "C";

  return (
    <Card shadow="md" padding={24} radius="xl" border>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface)">
              {city ?? "Unknown City"}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {condition ?? "Clear"}
            </Text>
          </Stack>
          <Box padding={8} background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
             <Text size="2xl">{forecast?.[0]?.icon ?? "☀️"}</Text>
          </Box>
        </Stack>

        {/* Main Temperature Section */}
        <Stack align="center" gap={0}>
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-primary-600)"
          >
            {Math.round(temperature ?? 0)}°{displayUnit}
          </Text>
        </Stack>

        {/* Details Row */}
        <Stack direction="horizontal" justify="around" align="center">
          <Stack gap={2} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface)">{humidity ?? 0}%</Text>
          </Stack>
          <Divider orientation="vertical" margin={12} />
          <Stack gap={2} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface)">{windSpeed ?? 0} km/h</Text>
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin={0} color="var(--ggui-color-outlineVariant)" />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center" gap={8} wrap>
          {(forecast ?? []).map((item, index) => (
            <Box 
              key={index} 
              padding={12} 
              borderRadius="var(--ggui-shape-radius-lg)"
              style={{ flex: '1 1 auto', textAlign: 'center' }}
            >
              <Stack gap={8} align="center">
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
                  {item.day ?? "Day"}
                </Text>
                <Text size="lg">{item.icon ?? "☀️"}</Text>
                <Stack gap={2} align="center">
                  <Text weight="semibold" size="sm" color="var(--ggui-color-onSurface)">
                    {item.high ?? 0}°
                  </Text>
                  <Text size="xs" color="var(--ggui-color-onSurfaceVariant)">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Progress,
  Divider,
  Box,
  Spacer,
  Badge,
  Alert
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions?: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels?: string[];
  /** Callback for submission */
  submit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string[];
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [
      "Dashboard Analytics",
      "Team Collaboration",
      "API Integration",
      "Custom Workflows",
      "Mobile App",
      "AI Assistance"
    ],
    satisfactionLabels = [
      "Very Unsatisfied",
      "Unsatisfied",
      "Neutral",
      "Satisfied",
      "Very Satisfied"
    ],
    submit
  } = props;

  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const totalSteps = 5; // 4 input steps + 1 review step

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(formData.email);
  const isNameValid = formData.name.trim().length > 0;

  const isStepValid = () => {
    switch (step) {
      case 0:
        return isNameValid && isEmailValid;
      case 1:
        return formData.satisfaction !== '';
      case 2:
        return true; // Features are optional
      case 3:
        return true; // Comments are optional
      default:
        return true;
    }
  };

  const handleNext = () => {
    if (isStepValid() && step < totalSteps - 1) {
      setStep((s) => s + 1);
    }
  };

  const handleBack = () => {
    if (step > 0) {
      setStep((s) => s - 1);
    }
  };

  const handleSubmit = () => {
    setIsSubmitting(true);
    const payload = {
      ...formData,
      satisfaction: parseInt(formData.satisfaction, 10),
      comments: [formData.comments] // Wrap in array as per contract implication or typical list logic
    };

    submit?.(payload as any);

    // Simulate submission success
    setTimeout(() => {
      setIsSubmitting(false);
      setSubmitted(true);
    }, 1000);
  };

  if (submitted) {
    return (
      <Container maxWidth="md" padding={24}>
        <Card padding={32} shadow="md">
          <Stack gap={24} align="center">
            <Box background="var(--ggui-color-success-50, #f0fdf4)" padding={16} borderRadius="var(--ggui-shape-radius-full, 9999px)">
              <Text color="var(--ggui-color-success-600, #16a34a)" size="4xl" weight="bold">✓</Text>
            </Box>
            <Stack gap={8} align="center">
              <Heading level={2}>Thank You!</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                Your survey response has been recorded successfully. We appreciate your feedback.
              </Text>
            </Stack>
            <Button variant="outline" onClick={() => {
              setStep(0);
              setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' });
              setSubmitted(false);
            }}>
              Submit Another Response
            </Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="end">
            <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
              Step {step + 1} of {totalSteps}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {Math.round(((step + 1) / totalSteps) * 100)}% Complete
            </Text>
          </Stack>
          <Progress value={step + 1} max={totalSteps} variant="primary" size="sm" />
        </Stack>

        <Card padding={24} shadow="sm" border>
          <Stack gap={24}>
            {step === 0 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Personal Information</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Please provide your contact details to start the survey.
                  </Text>
                </Stack>
                <Divider margin={0} />
                <Input
                  label="Full Name"
                  placeholder="e.g. John Doe"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                  required
                  error={formData.name.length > 0 && !isNameValid ? "Name is required" : undefined}
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="john@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  required
                  error={formData.email.length > 0 && !isEmailValid ? "Please enter a valid email" : undefined}
                />
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Satisfaction Level</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    How would you rate your overall experience with our platform?
                  </Text>
                </Stack>
                <Divider margin={0} />
                <RadioGroup
                  label="Rate your satisfaction"
                  value={formData.satisfaction}
                  onChange={(val) => setFormData({ ...formData, satisfaction: val })}
                  options={satisfactionLabels.map((label, i) => ({
                    value: String(i + 1),
                    label: label
                  }))}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Feature Interests</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Which features are you most interested in? (Select all that apply)
                  </Text>
                </Stack>
                <Divider margin={0} />
                <Box paddingX={4}>
                  <Stack gap={12}>
                    {featureOptions.map((opt) => (
                      <Checkbox
                        key={opt}
                        label={opt}
                        checked={formData.features.includes(opt)}
                        onChange={(checked) => {
                          const next = checked
                            ? [...formData.features, opt]
                            : formData.features.filter((f) => f !== opt);
                          setFormData({ ...formData, features: next });
                        }}
                      />
                    ))}
                  </Stack>
                </Box>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Final Comments</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Do you have any other feedback or suggestions for us?
                  </Text>
                </Stack>
                <Divider margin={0} />
                <TextArea
                  label="Comments"
                  placeholder="Share your thoughts here..."
                  value={formData.comments}
                  onChange={(val) => setFormData({ ...formData, comments: val })}
                  maxLength={500}
                  showCount
                  rows={6}
                />
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <Stack gap={4}>
                  <Heading level={3}>Review Your Answers</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Please verify your details before submitting the survey.
                  </Text>
                </Stack>
                <Divider margin={0} />

                <Stack gap={16}>
                  <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                    <Stack gap={12}>
                      <Stack gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Contact</Text>
                        <Text weight="medium">{formData.name} • {formData.email}</Text>
                      </Stack>
                      <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                      <Stack gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                        <Text weight="medium">
                          {satisfactionLabels[parseInt(formData.satisfaction, 10) - 1] ?? 'Not selected'} ({formData.satisfaction}/5)
                        </Text>
                      </Stack>
                      <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                      <Stack gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interests</Text>
                        <Stack direction="horizontal" gap={8} wrap>
                          {formData.features.length > 0 ? (
                            formData.features.map(f => <Badge key={f} variant="primary" size="sm">{f}</Badge>)
                          ) : (
                            <Text variant="caption" style={{ fontStyle: 'italic' }}>No features selected</Text>
                          )}
                        </Stack>
                      </Stack>
                      <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                      <Stack gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                        <Text weight="medium" truncate={false}>
                          {formData.comments.trim() || <Text variant="caption" style={{ fontStyle: 'italic' }}>No comments provided</Text>}
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>

                <Alert variant="info" title="Ready to submit?">
                  By clicking submit, your responses will be sent to our research team for analysis.
                </Alert>
              </Stack>
            )}

            <Stack direction="horizontal" gap={12} justify="end">
              {step > 0 && (
                <Button variant="secondary" onClick={handleBack} disabled={isSubmitting}>
                  Back
                </Button>
              )}
              <Spacer size="flex" />
              {step < totalSteps - 1 ? (
                <Button variant="primary" onClick={handleNext} disabled={!isStepValid()}>
                  Next Step
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>
                  Submit Survey
                </Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Box,
  Divider,
  Icon,
  Spacer
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  /** Array of tasks with id, title, priority, assignee, column ID, and optional dueDate */
  tasks: Task[];
  /** Column definitions */
  columns: Column[];
  /** Callback for task updates */
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent({
  tasks = [],
  columns = [],
  onTaskUpdate = () => {}
}: Props) {
  // Local state for adding tasks
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState('medium');

  // Internal state for "editing" mode
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const totalTasks = tasks?.length ?? 0;
  const completedCount = tasks?.filter((t) => t.column === 'done' || t.column?.includes('done'))?.length ?? 0;

  const handleAddTask = (columnId: string) => {
    if (!newTitle.trim()) return;

    const newTask = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      priority: newPriority as 'low' | 'medium' | 'high',
      column: columnId,
      assignee: '??'
    };

    onTaskUpdate({
      action: 'create',
      data: newTask
    });

    setAddingToColumn(null);
    setNewTitle('');
    setNewPriority('medium');
  };

  const handleMoveTask = (taskId: string, newColumnId: string) => {
    onTaskUpdate({
      action: 'move',
      taskId,
      data: { column: newColumnId }
    });
  };

  const handleSaveEdit = (taskId: string) => {
    onTaskUpdate({
      action: 'edit',
      taskId,
      data: { title: editTitle }
    });
    setEditingTaskId(null);
  };

  const priorityVariants: Record<string, 'success' | 'warning' | 'error'> = {
    low: 'success',
    medium: 'warning',
    high: 'error'
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding={16} shadow="sm">
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="horizontal" align="center" gap={12}>
              <Icon name="menu" size={20} color="var(--ggui-color-primary-600)" />
              <Heading level={3}>Task Board</Heading>
            </Stack>
            <Stack direction="horizontal" gap={16}>
              <Box paddingX={12} paddingY={4} background="var(--ggui-color-primary-50)" borderRadius={999}>
                <Text variant="label" color="var(--ggui-color-primary-700)">
                  Total: {totalTasks}
                </Text>
              </Box>
              <Box paddingX={12} paddingY={4} background="var(--ggui-color-success-50)" borderRadius={999}>
                <Text variant="label" color="var(--ggui-color-success-700)">
                  Completed: {completedCount}
                </Text>
              </Box>
            </Stack>
          </Stack>
        </Card>

        {/* Kanban Board */}
        <Stack direction="horizontal" gap={20} align="start" justify="start">
          {columns?.map((col) => {
            const columnTasks = tasks?.filter((t) => t.column === col.id) ?? [];
            return (
              <Box
                key={col.id}
                style={{
                  flex: '1 1 300px',
                  minWidth: '280px',
                  maxWidth: '400px',
                  background: 'var(--ggui-color-neutral-100)',
                  borderRadius: 'var(--ggui-shape-radius-xl)',
                  padding: '16px'
                }}
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={4}>{col.name ?? 'Untitled'}</Heading>
                    <Badge variant="secondary">{columnTasks.length}</Badge>
                  </Stack>

                  <Divider margin={4} />

                  {/* Task List */}
                  <Stack gap={12}>
                    {columnTasks.map((task) => (
                      <Card key={task.id} padding={12} shadow="sm" radius="md" border={true}>
                        <Stack gap={12}>
                          {editingTaskId === task.id ? (
                            <Stack gap={8}>
                              <Input
                                label="Edit Task Title"
                                value={editTitle}
                                onChange={setEditTitle}
                                autoFocus
                              />
                              <Stack direction="horizontal" gap={8} justify="end">
                                <Button size="sm" variant="ghost" onPress={() => setEditingTaskId(null)}>
                                  Cancel
                                </Button>
                                <Button size="sm" onPress={() => handleSaveEdit(task.id!)}>
                                  Save
                                </Button>
                              </Stack>
                            </Stack>
                          ) : (
                            <Stack gap={8}>
                              <Stack direction="horizontal" justify="between" align="start">
                                <Box style={{ flex: 1 }}>
                                  <Text weight="semibold" variant="body">
                                    {task.title}
                                  </Text>
                                </Box>
                                <Button
                                  size="xs"
                                  variant="ghost"
                                  onPress={() => {
                                    setEditingTaskId(task.id!);
                                    setEditTitle(task.title ?? '');
                                  }}
                                >
                                  <Icon name="settings" size={14} />
                                </Button>
                              </Stack>

                              <Stack direction="horizontal" align="center" justify="between">
                                <Badge variant={priorityVariants[task.priority ?? 'medium']} size="sm">
                                  {task.priority?.toUpperCase()}
                                </Badge>
                                {task.dueDate && (
                                  <Text variant="caption" color="var(--ggui-color-neutral-500)">
                                    Due {task.dueDate}
                                  </Text>
                                )}
                              </Stack>

                              <Divider margin={4} />

                              <Stack direction="horizontal" align="center" justify="between">
                                <Avatar name={task.assignee} size="xs" />
                                <Box style={{ width: '120px' }}>
                                  <Select
                                    size="sm"
                                    value={task.column}
                                    onChange={(val) => handleMoveTask(task.id!, val)}
                                    options={columns.map((c) => ({
                                      value: c.id ?? '',
                                      label: `Move to ${c.name}`
                                    }))}
                                  />
                                </Box>
                              </Stack>
                            </Stack>
                          )}
                        </Stack>
                      </Card>
                    ))}

                    {/* Add Task Form */}
                    {addingToColumn === col.id ? (
                      <Card padding={16} shadow="md" border={true}>
                        <Stack gap={12}>
                          <Input
                            label="New Task Title"
                            placeholder="What needs to be done?"
                            value={newTitle}
                            onChange={setNewTitle}
                            required
                          />
                          <Select
                            label="Priority"
                            value={newPriority}
                            onChange={setNewPriority}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' }
                            ]}
                          />
                          <Stack direction="horizontal" gap={8} justify="end">
                            <Button variant="ghost" size="sm" onPress={() => setAddingToColumn(null)}>
                              Cancel
                            </Button>
                            <Button size="sm" onPress={() => handleAddTask(col.id!)}>
                              Add Task
                            </Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : (
                      <Button
                        variant="outline"
                        fullWidth
                        leftIcon={<Icon name="plus" size={16} />}
                        onPress={() => setAddingToColumn(col.id!)}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Input,
  Spacer,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const CATEGORY_COLORS: Record<string, { bg: string; border: string; text: string }> = {
  nonmetal: {
    bg: 'var(--ggui-color-success-50, #f0fdf4)',
    border: 'var(--ggui-color-success-200, #bbf7d0)',
    text: 'var(--ggui-color-success-800, #166534)',
  },
  'noble-gas': {
    bg: 'var(--ggui-color-primary-50, #f0f9ff)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
    text: 'var(--ggui-color-primary-800, #075985)',
  },
  'alkali-metal': {
    bg: 'var(--ggui-color-error-50, #fef2f2)',
    border: 'var(--ggui-color-error-200, #fecaca)',
    text: 'var(--ggui-color-error-800, #991b1b)',
  },
  'alkaline-earth-metal': {
    bg: 'var(--ggui-color-warning-50, #fffbeb)',
    border: 'var(--ggui-color-warning-200, #fde68a)',
    text: 'var(--ggui-color-warning-800, #92400e)',
  },
  metalloid: {
    bg: 'var(--ggui-color-info-50, #ecfeff)',
    border: 'var(--ggui-color-info-200, #a5f3fc)',
    text: 'var(--ggui-color-info-800, #155e75)',
  },
  halogen: {
    bg: 'var(--ggui-color-primary-100, #e0f2fe)',
    border: 'var(--ggui-color-primary-300, #7dd3fc)',
    text: 'var(--ggui-color-primary-900, #0c4a6e)',
  },
  'transition-metal': {
    bg: 'var(--ggui-color-neutral-50, #f9fafb)',
    border: 'var(--ggui-color-neutral-200, #e5e7eb)',
    text: 'var(--ggui-color-neutral-700, #374151)',
  },
  'post-transition-metal': {
    bg: 'var(--ggui-color-neutral-100, #f3f4f6)',
    border: 'var(--ggui-color-neutral-300, #d1d5db)',
    text: 'var(--ggui-color-neutral-900, #111827)',
  },
  lanthanide: {
    bg: 'var(--ggui-color-info-100, #cffafe)',
    border: 'var(--ggui-color-info-300, #67e8f9)',
    text: 'var(--ggui-color-info-900, #083344)',
  },
  actinide: {
    bg: 'var(--ggui-color-error-100, #fee2e2)',
    border: 'var(--ggui-color-error-300, #fca5a5)',
    text: 'var(--ggui-color-error-900, #450a0a)',
  },
};

const DEFAULT_COLOR = {
  bg: 'var(--ggui-color-neutral-50, #f9fafb)',
  border: 'var(--ggui-color-neutral-200, #e5e7eb)',
  text: 'var(--ggui-color-neutral-900, #111827)',
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const lower = search.toLowerCase();
    return elements.filter(
      (el) => el.name?.toLowerCase().includes(lower) || el.symbol?.toLowerCase().includes(lower)
    );
  }, [elements, search]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set);
  }, [elements]);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Box paddingY={8} style={{ maxWidth: '400px' }}>
            <Input
              label="Search Elements"
              placeholder="Filter by name or symbol..."
              value={search}
              onChange={setSearch}
            />
          </Box>
        </Stack>

        <Stack direction="horizontal" wrap gap={8} align="center">
          <Text variant="label">Legend:</Text>
          {categories.map((cat) => {
            const colors = CATEGORY_COLORS[cat] ?? DEFAULT_COLOR;
            return (
              <Box
                key={cat}
                paddingX={8}
                paddingY={4}
                borderRadius="var(--ggui-shape-radius-sm, 4px)"
                style={{
                  background: colors.bg,
                  border: `1px solid ${colors.border}`,
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  color: colors.text,
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                }}
              >
                {cat.replace('-', ' ')}
              </Box>
            );
          })}
        </Stack>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            paddingBottom: '16px',
          }}
        >
          {filteredElements.map((el) => {
            const colors = CATEGORY_COLORS[el.category ?? ''] ?? DEFAULT_COLOR;
            const isSelected = selected?.atomicNumber === el.atomicNumber;

            return (
              <div
                key={el.atomicNumber}
                onClick={() => setSelected(el)}
                style={{
                  gridRow: el.row ?? 'auto',
                  gridColumn: el.col ?? 'auto',
                  cursor: 'pointer',
                  aspectRatio: '1 / 1',
                  minWidth: '50px',
                }}
              >
                <Box
                  padding={4}
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  style={{
                    height: '100%',
                    background: colors.bg,
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : colors.border}`,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    transition: 'all 0.2s ease',
                    position: 'relative',
                  }}
                >
                  <Text
                    size="xs"
                    weight="semibold"
                    color={colors.text}
                    style={{ position: 'absolute', top: '4px', left: '4px' }}
                  >
                    {el.atomicNumber}
                  </Text>
                  <Spacer size={8} />
                  <Text
                    align="center"
                    weight="bold"
                    size="xl"
                    color={colors.text}
                    style={{ lineHeight: 1 }}
                  >
                    {el.symbol}
                  </Text>
                  <Text
                    align="center"
                    truncate
                    style={{
                      fontSize: '8px',
                      color: colors.text,
                      opacity: 0.8,
                    }}
                  >
                    {el.name}
                  </Text>
                </Box>
              </div>
            );
          })}
        </div>

        {selected && (
          <div style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Card shadow="md" padding={24}>
              <Stack gap={16}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Stack gap={4}>
                    <Heading level={3}>{selected.name}</Heading>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      Atomic Number {selected.atomicNumber}
                    </Text>
                  </Stack>
                  <Badge variant="primary" size="lg">
                    {selected.category?.replace('-', ' ') ?? 'Unknown'}
                  </Badge>
                </Stack>

                <Divider margin={0} />

                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
                    gap: 'var(--ggui-spacing-6, 24px)',
                  }}
                >
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                      Symbol
                    </Text>
                    <Text weight="bold" size="2xl">
                      {selected.symbol}
                    </Text>
                  </Stack>
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                      Atomic Weight
                    </Text>
                    <Text weight="semibold" size="lg">
                      {selected.atomicWeight} u
                    </Text>
                  </Stack>
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                      Grid Location
                    </Text>
                    <Text weight="semibold">
                      Row {selected.row}, Column {selected.col}
                    </Text>
                  </Stack>
                </div>
              </Stack>
            </Card>
          </div>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
