interface Props {
  /** Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[] */
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: unknown[];
    reviews?: unknown[];
  };
  /** Callback to add item to cart */
  addToCart: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  product = {
    id: "prod-001",
    name: "Wireless Noise-Cancelling Headphones",
    price: 249.99,
    currency: "USD",
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: "Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.",
    specifications: [
      { key: "Brand", value: "AudioMax" },
      { key: "Battery Life", value: "30 hours" }
    ],
    reviews: [
      { author: "Alex M.", rating: 5, text: "Best headphones I have ever owned. The noise cancellation is incredible.", date: "2026-03-01" }
    ]
  },
  addToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Handle agent data streaming if necessary
  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Received agent data:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleAddToCart = () => {
    if (product?.id) {
      addToCart({ productId: product.id, quantity });
    }
  };

  // Helper for stars
  const RatingStars = ({ rating = 0 }: { rating?: number }) => (
    <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon
          key={star}
          size={16}
          color={star <= Math.round(rating) ? "var(--ggui-color-warning-500, #f59e0b)" : "var(--ggui-color-neutral-300, #d1d5db)"}
        >
          <svg viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" />
          </svg>
        </Icon>
      ))}
    </Stack>
  );

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY="var(--ggui-spacing-4, 16px)">
          <Text variant="body">{product?.description ?? "No description available."}</Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY="var(--ggui-spacing-4, 16px)">
          <Table
            columns={[
              { key: 'key', header: 'Specification', width: '40%' },
              { key: 'value', header: 'Value' },
            ]}
            data={(product?.specifications as any[]) ?? []}
            bordered
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-4, 16px)">
          {((product?.reviews as any[]) ?? []).map((review, idx) => (
            <Card key={idx} padding="var(--ggui-spacing-4, 16px)" shadow="none" border>
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label">{review?.author ?? "Anonymous"}</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {review?.date ?? ""}
                  </Text>
                </Stack>
                <RatingStars rating={review?.rating} />
                <Text variant="bodySmall">{review?.text ?? ""}</Text>
              </Stack>
            </Card>
          ))}
          {(!product?.reviews || product.reviews.length === 0) && (
            <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No reviews available for this product.
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  const inStock = (product?.stock ?? 0) > 0;
  const isLowStock = (product?.stock ?? 0) > 0 && (product?.stock ?? 0) <= 5;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Top Product Hero Section */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="start" wrap>
          {/* Image Area */}
          <Box
            style={{
              flex: '1 1 400px',
              minHeight: '400px',
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              textAlign: 'center',
              padding: 'var(--ggui-spacing-6, 24px)',
            }}
          >
            <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
              {product?.name ?? "Product Image"}
            </Heading>
          </Box>

          {/* Details Area */}
          <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: '1 1 300px' }}>
