                <Text variant="label">Select Quantity</Text>
                <Stack direction="horizontal" align="center" gap="0">
                  <Button
                    variant="secondary"
                    size="md"
                    disabled={quantity <= 1 || !inStock}
                    onPress={() => setQuantity((q) => q - 1)}
                    style={{ borderTopRightRadius: 0, borderBottomRightRadius: 0 }}
                  >
                    <Icon name="minus" size={16} />
                  </Button>
                  <Box
                    style={{
                      width: '64px',
                      height: '40px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <Text weight="medium">{quantity}</Text>
                  </Box>
                  <Button
                    variant="secondary"
                    size="md"
                    disabled={quantity >= (product?.stock ?? 0) || !inStock}
                    onPress={() => setQuantity((q) => q + 1)}
                    style={{ borderTopLeftRadius: 0, borderBottomLeftRadius: 0 }}
                  >
                    <Icon name="plus" size={16} />
                  </Button>
                </Stack>
              </Stack>

              {/* Action Button */}
              <Button
                variant="primary"
                size="lg"
                fullWidth
                disabled={!inStock}
                onPress={handleAddToCart}
                leftIcon={<Icon name="plus" size={20} />}
              >
                {inStock ? "Add to Cart" : "Currently Unavailable"}
              </Button>
            </Stack>
          </Stack>
        </Stack>

        {/* Tabbed Product Information */}
        <Card padding="var(--ggui-spacing-6, 24px)" radius="xl" shadow="sm">
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            fullWidth
          />
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Button,
  Badge,
  Spacer,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Called when user sends a message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'You',
    participantCount,
    messages = [],
    onSendMessage
  } = props;

  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on mount and when messages change
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Listen for ggui:agent-data events
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      console.log('ggui:agent-data received:', customEvent.detail);
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleSend = () => {
    const text = inputValue.trim();
    if (text && onSendMessage) {
      onSendMessage({
        text,
        timestamp: new Date().toISOString()
      });
      setInputValue('');
    }
  };

  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      return new Date(timestamp).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (e) {
      return '';
    }
  };

  return (
    <Container maxWidth="md" padding={16}>
      <MotionKeyframes />
      <Card
        padding={0}
        radius="xl"
        shadow="lg"
        border
      >
        <Stack gap={0} style={{ height: '600px', maxHeight: '80vh' }}>
          {/* Header */}
          <Box
            padding={16}
            background="var(--ggui-color-surface, #fafafa)"
            style={{
              borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderTopLeftRadius: 'var(--ggui-shape-radius-xl)',
              borderTopRightRadius: 'var(--ggui-shape-radius-xl)'
            }}
          >
            <Stack direction="horizontal" align="center" justify="between">
              <Stack direction="horizontal" align="center" gap={8}>
                <Heading level={4}>{title ?? 'Team Chat'}</Heading>
                {(participantCount ?? 0) > 0 && (
                  <Badge variant="primary" size="sm">
                    {participantCount} participants
                  </Badge>
                )}
              </Stack>
            </Stack>
          </Box>

          {/* Message List */}
          <Box
            ref={scrollRef}
            padding={16}
            style={{
              flex: 1,
              overflowY: 'auto',
              background: 'var(--ggui-color-surface, #fafafa)'
            }}
          >
            <Stack gap={12}>
              {messages.map((msg, i) => {
                const isMe = msg.sender === currentUser;
                const isConsecutive = i > 0 && messages[i - 1].sender === msg.sender;

                return (
                  <Stack
                    key={`${msg.timestamp}-${i}`}
                    align={isMe ? 'end' : 'start'}
                    gap={2}
                    style={{
                      animation: 'ggui-fadeIn 200ms ease-out'
                    }}
                  >
                    {!isMe && !isConsecutive && (
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        {msg.sender ?? 'Anonymous'}
                      </Text>
                    )}
                    <Box
                      paddingX={12}
                      paddingY={8}
                      borderRadius={12}
                      background={
                        isMe
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      style={{
                        maxWidth: '80%',
                        borderBottomRightRadius: isMe && !isConsecutive ? 0 : 12,
                        borderBottomLeftRadius: !isMe && !isConsecutive ? 0 : 12
                      }}
                    >
                      <Text
                        variant="bodySmall"
                        color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {msg.text ?? ''}
                      </Text>
                    </Box>
                    <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Box>

          {/* Input Area */}
          <Box
            padding={16}
            background="var(--ggui-color-surface, #fafafa)"
            style={{
              borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderBottomLeftRadius: 'var(--ggui-shape-radius-xl)',
              borderBottomRightRadius: 'var(--ggui-shape-radius-xl)'
            }}
          >
            <Stack direction="horizontal" align="end" gap={12}>
              <div style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type your message..."
                  value={inputValue}
                  onChange={(val) => setInputValue(val)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                />
              </div>
              <Button
                variant="primary"
                onPress={handleSend}
                disabled={!inputValue.trim()}
              >
                Send
              </Button>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Icon,
  Divider,
  Spacer,
  Spinner,
  Badge
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnecting, setIsConnecting] = useState(initialStocks.length === 0);

  useEffect(() => {
    // Initial sync
    setStocks(initialStocks);
    if (initialStocks.length > 0) {
      setIsConnecting(false);
    }
  }, [initialStocks]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data && data.stocks) {
        setStocks(data.stocks);
        setLastUpdated(new Date().toISOString());
        setIsConnecting(false);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatPrice = (value?: number) => {
    return (value ?? 0).toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });
  };

  const formatLastUpdated = (iso?: string) => {
    if (!iso) return '--:--:--';
    try {
      return new Date(iso).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return '--:--:--';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Badge variant={isConnecting ? 'warning' : 'success'} size="sm">
                {isConnecting ? 'Connecting...' : 'Live Data'}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formatLastUpdated(lastUpdated)}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* State Management: Loading vs Grid */}
        {isConnecting && stocks.length === 0 ? (
          <Box paddingY={64}>
            <Stack align="center" gap={16}>
              <Spinner size={40} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Initializing secure market data stream...
              </Text>
            </Stack>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3 }} gap={20}>
            {stocks.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const statusColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const borderColor = isPositive
                ? 'var(--ggui-color-success-500, #22c55e)'
                : 'var(--ggui-color-error-500, #ef4444)';

              return (
                <Card
                  key={`${stock.symbol}-${index}`}
                  padding={20}
                  radius="lg"
                  shadow="sm"
                  style={{
                    borderLeft: `4px solid ${borderColor}`,
                    animation: `ggui-fadeIn 400ms ease-out ${index * 60}ms both`,
                    background: 'var(--ggui-color-surface, #fafafa)',
                  } as React.CSSProperties}
                >
                  <Stack gap={12}>
                    {/* Symbol & Performance Badge */}
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={0}>
                        <Text
                          weight="bold"
                          size="2xl"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {stock.symbol ?? 'N/A'}
                        </Text>
                        <Text
                          variant="bodySmall"
                          truncate
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        >
                          {stock.name ?? 'Unknown Company'}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" align="center" gap={4}>
                        <Icon
                          name={isPositive ? 'chevron-up' : 'chevron-down'}
                          size={14}
                          color={statusColor}
                        />
                        <Text weight="semibold" size="sm" color={statusColor}>
                          {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                        </Text>
                      </Stack>
                    </Stack>

                    <Divider
                      margin={4}
                      color="var(--ggui-color-outlineVariant, #e4e4e7)"
                    />

                    {/* Pricing Data */}
                    <Stack direction="horizontal" align="end">
                      <Stack gap={0}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Current Price
                        </Text>
                        <Text
                          size="3xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          ${formatPrice(stock.price)}
                        </Text>
                      </Stack>
                      <Spacer size="flex" />
                      <Box>
                        <Text variant="label" weight="medium" color={statusColor}>
                          {isPositive ? '+' : ''}
                          {formatPrice(stock.change)}
                        </Text>
                      </Box>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Toggle,
  Select,
  Progress,
  Spacer,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';
import { FormField } from '@ggui-ai/design/components';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  /** Pre-filled profile data for editing */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all profile data when user completes onboarding */
  onComplete?: (data: ProfileData) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
  roleOptions = ["Developer", "Designer", "Manager", "Other"],
  onComplete,
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? avatarOptions[0],
    role: initialProfile?.role ?? roleOptions[0],
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = useMemo(() => {
    return formData.name.trim().length > 0 && isEmailValid(formData.email);
  }, [formData.name, formData.email]);

  const handleNext = () => {
    if (step < 3) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleSubmit = () => {
    onComplete?.(formData);
  };

  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Step Indicator Header */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={4}>
              Step {step} of 3
            </Heading>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
              {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}
            </Text>
          </Stack>
          <Progress value={progressValue} size="sm" variant="primary" />
        </Stack>

        <Card padding={32} shadow="md" radius="xl" border>
          <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }} key={step}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Set up your profile</Heading>
                <FormField label="Full Name" required description="How should we address you?">
                  <Input
                    label="Full Name"
                    placeholder="Enter your name"
                    value={formData.name}
                    onChange={(val) => setFormData({ ...formData, name: val })}
                  />
                </FormField>

                <FormField 
                  label="Email Address" 
                  required 
                  error={formData.email && !isEmailValid(formData.email) ? "Please enter a valid email" : undefined}
                >
                  <Input
                    label="Email Address"
                    type="email"
                    placeholder="you@example.com"
                    value={formData.email}
                    onChange={(val) => setFormData({ ...formData, email: val })}
                  />
                </FormField>

                <Stack gap={12}>
                  <Text variant="label">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap={16} wrap>
                    {avatarOptions.map((emoji) => (
                      <Box
                        key={emoji}
                        padding={12}
                        borderRadius="var(--ggui-shape-radius-full, 9999px)"
                        background={formData.avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-neutral-50, #f9fafb)'}
                        style={{
                          cursor: 'pointer',
                          border: formData.avatar === emoji 
                            ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                            : '2px solid transparent',
                          transition: 'all 200ms ease',
                          fontSize: '24px',
                          width: '56px',
                          height: '56px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center'
                        }}
                        onClick={() => setFormData({ ...formData, avatar: emoji })}
                      >
                        {emoji}
                      </Box>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Personalize your experience</Heading>

                <FormField label="Current Role" description="Select the role that best fits you">
                  <Select
                    label="Current Role"
                    options={roleOptions.map(r => ({ value: r, label: r }))}
                    value={formData.role}
                    onChange={(val) => setFormData({ ...formData, role: val })}
                  />
                </FormField>

                <Card variant="default" padding={16} radius="md" border>
                  <Stack gap={16}>
                    <Toggle
                      label="Email Notifications"
                      checked={formData.emailNotifications}
                      onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
                    />
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      Get updates about your project activity via email.
                    </Text>
                  </Stack>
                </Card>

                <Card variant="default" padding={16} radius="md" border>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack gap={4}>
                      <Text variant="label">Theme Preference</Text>
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                        Switch between light and dark visual styles.
                      </Text>
                    </Stack>
                    <Toggle
                      label={formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'}
                      checked={formData.theme === 'dark'}
                      onChange={(isDark) => setFormData({ ...formData, theme: isDark ? 'dark' : 'light' })}
                    />
                  </Stack>
                </Card>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Review your details</Heading>

                <Box padding={20} background="var(--ggui-color-neutral-50, #f9fafb)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
                  <Stack gap={16}>
                    <Stack direction="horizontal" align="center" gap={16}>
                      <Box 
                        fontSize="32px" 
                        background="var(--ggui-color-white, #ffffff)" 
                        borderRadius="9999px" 
                        padding={12}
                        style={{ border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}
                      >
                        {formData.avatar}
                      </Box>
                      <Stack gap={4}>
                        <Text weight="semibold" size="lg">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{formData.email}</Text>
                      </Stack>
                    </Stack>

                    <Stack gap={8} style={{ borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', paddingTop: '16px' }}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Role</Text>
                        <Text weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Notifications</Text>
                        <Text weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Theme</Text>
                        <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>

                <Box padding={12} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="8px">
                  <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)" align="center">
                    You can update these settings anytime in your account preferences.
                  </Text>
                </Box>
              </Stack>
            )}
          </div>

          <Spacer size={32} />

          {/* Navigation Controls */}
          <Stack direction="horizontal" justify="between">
            {step > 1 ? (
              <Button variant="outline" onClick={handleBack} size="md">
                {step === 3 ? 'Go Back' : 'Previous'}
              </Button>
            ) : (
              <div />
            )}

            {step < 3 ? (
              <Button 
                variant="primary" 
                onClick={handleNext} 
                disabled={step === 1 && !isStep1Valid}
                size="md"
              >
                Next Step
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} size="md">
                Complete Setup
              </Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

