import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Divider } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

const DEFAULT_FEATURE_OPTIONS = [
  "Dashboard Analytics",
  "Team Collaboration",
  "API Integration",
  "Custom Workflows",
  "Mobile App",
  "AI Assistance"
];

const DEFAULT_SATISFACTION_LABELS = [
  "Very Unsatisfied",
  "Unsatisfied",
  "Neutral",
  "Satisfied",
  "Very Satisfied"
];

export default function GeneratedComponent({
  featureOptions = DEFAULT_FEATURE_OPTIONS,
  satisfactionLabels = DEFAULT_SATISFACTION_LABELS,
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateStep1 = () => {
    let isValid = true;
    const newErrors = { name: '', email: '' };
    if (!formData.name) { newErrors.name = 'Name is required'; isValid = false; }
    if (!formData.email) { newErrors.email = 'Email is required'; isValid = false; }
    else if (!isEmailValid(formData.email)) { newErrors.email = 'Invalid email format'; isValid = false; }
    setErrors(newErrors);
    return isValid;
  };

  const handleNext = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => Math.min(s + 1, 5));
  };

  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const satisfactionOptions = satisfactionLabels.map((label, i) => ({
    value: (i + 1).toString(),
    label: `${i + 1}: ${label}`
  }));

  return (
    <Card shadow="md" padding={32} radius="lg">
      <Stack gap={24}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-neutral-500)">
            Step {step} of 5
          </Text>
          <Progress value={(step / 5) * 100} size="md" />
        </Stack>

        {step === 1 && (
          <Stack gap={16}>
            <Heading level={3}>Personal Details</Heading>
            <Input 
              label="Name" 
              required 
              value={formData.name} 
              onChange={(v) => setFormData({...formData, name: v})} 
              error={errors.name} 
            />
            <Input 
              label="Email" 
              required 
              type="email" 
              value={formData.email} 
              onChange={(v) => setFormData({...formData, email: v})} 
              error={errors.email} 
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={16}>
            <Heading level={3}>Satisfaction Rating</Heading>
            <RadioGroup
              label="How satisfied are you?"
              value={formData.satisfaction.toString()}
              onChange={(v) => setFormData({...formData, satisfaction: parseInt(v)})}
              options={satisfactionOptions}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={16}>
            <Heading level={3}>Feature Interests</Heading>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={formData.features.includes(feature)}
                onChange={(checked) => {
                  setFormData((prev) => ({
                    ...prev,
                    features: checked 
                      ? [...prev.features, feature]
                      : prev.features.filter((f) => f !== feature)
                  }));
                }}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={16}>
            <Heading level={3}>Comments</Heading>
            <TextArea
              label="Open-ended comments"
              value={formData.comments}
              onChange={(v) => setFormData({...formData, comments: v})}
              maxLength={500}
              showCount
              rows={5}
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={16}>
            <Heading level={3}>Review</Heading>
            <Stack gap={8}>
              <Text><strong>Name:</strong> {formData.name}</Text>
              <Text><strong>Email:</strong> {formData.email}</Text>
              <Text><strong>Satisfaction:</strong> {formData.satisfaction}</Text>
              <Text><strong>Features:</strong> {formData.features.join(', ') || 'None'}</Text>
              <Text><strong>Comments:</strong> {formData.comments || 'None'}</Text>
            </Stack>
          </Stack>
        )}

        <Divider />
        <Stack direction="horizontal" gap={16} justify="between">
          <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 5 ? (
            <Button variant="primary" onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => onSubmit && onSubmit({
              name: formData.name,
              email: formData.email,
              satisfaction: formData.satisfaction,
              features: formData.features,
              comments: formData.comments
            })}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Button, Input, Select, Badge, Avatar, Divider, Box, Heading } from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: string; taskId: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { tasks = [], columns = [], onTaskUpdate } = props;
  const [taskList, setTaskList] = useState(tasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const handleTaskUpdate = (action: string, taskId: string, data: any) => {
    onTaskUpdate?.({ action, taskId, data });

    if (action === 'move') {
      setTaskList(prev => prev.map(t => t.id === taskId ? { ...t, column: data.column } : t));
    }
  };

  const handleAddTask = (columnId: string) => {
    if (!newTitle.trim()) return;
    const newTask = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      priority: newPriority,
      column: columnId,
      assignee: '??',
    };
    setTaskList(prev => [...prev, newTask]);
    onTaskUpdate?.({ action: 'create', taskId: newTask.id!, data: newTask });
    setIsAdding(null);
    setNewTitle('');
  };

  const totalTasks = taskList.length;
  const completedTasks = taskList.filter(t => t.column === 'done').length;

  return (
    <Stack gap={24} padding={24}>
      <Card padding={16}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>Task Board</Heading>
          <Text variant="bodySmall">
            {completedTasks} / {totalTasks} tasks completed
          </Text>
        </Stack>
      </Card>

      <Stack direction="horizontal" gap={16} align="start" wrap>
        {columns.map(col => {
          const colTasks = taskList.filter(t => t.column === col.id);
          return (
            <Box key={col.id} style={{ flex: 1, minWidth: 300 }}>
              <Stack gap={12}>
                <Stack direction="horizontal" justify="between">
                  <Text variant="label">{col.name} ({colTasks.length})</Text>
                </Stack>

                <Stack gap={8}>
                  {colTasks.map(task => (
                    <Card key={task.id} padding={12} shadow="sm">
                      <Stack gap={8}>
                        <Text variant="bodySmall" weight="medium">{task.title}</Text>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'} size="sm">
                            {task.priority}
                          </Badge>
                          <Avatar name={task.assignee ?? '??'} size={24} />
                        </Stack>
                        <Divider margin={0} />
                        <Select 
                          value={task.column ?? ''} 
                          onChange={(val) => handleTaskUpdate('move', task.id!, { column: val })}
                          options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                          size="sm"
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {isAdding === col.id ? (
                  <Card padding={12} border={true}>
                    <Stack gap={8}>
                      <Input value={newTitle} onChange={setNewTitle} placeholder="Task title..." />
                      <Select value={newPriority} onChange={(v) => setNewPriority(v as any)} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
                      <Stack direction="horizontal" gap={8}>
                        <Button size="sm" onClick={() => handleAddTask(col.id!)}>Add</Button>
                        <Button size="sm" variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="ghost" size="sm" onClick={() => setIsAdding(col.id!)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          );
        })}
      </Stack>
    </Stack>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Input, Box, Divider } from '@ggui-ai/design/primitives';

interface Element {
