  'noble-gas': 'var(--ggui-color-error-200)',
  'lanthanide': 'var(--ggui-color-primary-100)',
  'actinide': 'var(--ggui-color-primary-100)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = elements.filter(
    (el) =>
      el.name?.toLowerCase().includes(search.toLowerCase()) ||
      el.symbol?.toLowerCase().includes(search.toLowerCase())
  );

  const categories = Array.from(new Set(elements.map((e) => e.category).filter(Boolean)));

  return (
    <Stack gap={24} padding={24}>
      <Input
        label="Search Elements"
        placeholder="Name or Symbol..."
        value={search}
        onChange={setSearch}
        type="search"
      />

      <Box style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
        gap: '4px',
        overflowX: 'auto'
      }}>
        {filteredElements.map((el) => (
          <Box
            key={el.atomicNumber}
            style={{
              gridRow: el.row,
              gridColumn: el.col,
              aspectRatio: '1/1',
              backgroundColor: el.category ? CATEGORY_COLORS[el.category] || 'var(--ggui-color-neutral-100)' : 'var(--ggui-color-neutral-100)',
              cursor: 'pointer',
              display: 'flex',
              flexDirection: 'column',
              padding: '4px',
              borderRadius: 'var(--ggui-shape-radius-sm, 4px)'
            }}
            onClick={() => setSelectedElement(el)}
          >
            <Text variant="caption">{el.atomicNumber}</Text>
            <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <Heading level={6}>{el.symbol}</Heading>
            </Box>
          </Box>
        ))}
      </Box>

      <Stack direction="horizontal" wrap gap={12}>
        {categories.map((cat) => (
          <Stack key={cat} direction="horizontal" align="center" gap={4}>
            <Box style={{ width: 12, height: 12, backgroundColor: CATEGORY_COLORS[cat as string] || 'var(--ggui-color-neutral-100)', borderRadius: '2px' }} />
            <Text variant="caption">{cat}</Text>
          </Stack>
        ))}
      </Stack>

      {selectedElement && (
        <Card padding={24}>
          <Stack gap={16}>
            <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
            <Divider />
            <Stack direction="horizontal" gap={32}>
              <Box>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Number</Text>
                <Text>{selectedElement.atomicNumber}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Weight</Text>
                <Text>{selectedElement.atomicWeight}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Category</Text>
                <Text>{selectedElement.category}</Text>
              </Box>
            </Stack>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Divider, 
  Badge, 
  Tabs,
  Icon
} from '@ggui-ai/design/primitives';

interface ProductReview {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface ProductSpec {
  key: string;
  value: string;
}

interface Props {
  product?: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: any[];
    reviews?: any[];
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    product = {
      id: "prod-001",
      name: "Wireless Noise-Cancelling Headphones",
      price: 249.99,
      currency: "USD",
      rating: 4.3,
      reviewCount: 128,
      stock: 12,
      description: "Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.",
      specifications: [{ key: "Brand", value: "AudioMax" }, { key: "Battery Life", value: "30 hours" }],
      reviews: [{ author: "Alex M.", rating: 5, text: "Best headphones ever.", date: "2026-03-01" }]
    },
    onAddToCart = () => {}
  } = props;

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const {
    id = "prod-001",
    name = "Product",
    price = 0,
    currency = "USD",
    rating = 0,
    reviewCount = 0,
    stock = 0,
    description = "",
    specifications = [],
    reviews = []
  } = product;

  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock < 5;

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }).map((_, i) => (
      <Icon 
        key={i} 
        name="check"
        size={16} 
        color={i < Math.round(rating) ? "var(--ggui-color-warning-500, #f59e0b)" : "var(--ggui-color-neutral-300, #d1d5db)"} 
      />
    ));
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: <Text variant="body">{description}</Text>
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Stack gap={8}>
          {specifications.map((spec: any, i: number) => (
            <Box key={i} paddingY={4}>
              <Text variant="label" as="span">{spec.key}: </Text>
              <Text variant="body" as="span">{spec.value}</Text>
            </Box>
          ))}
        </Stack>
      )
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap={16}>
          {reviews.map((review: any, i: number) => (
            <Card key={i} padding={12} shadow="sm">
              <Stack gap={4}>
                <Text variant="label">{review.author} • {review.date}</Text>
                <Stack direction="horizontal">{renderStars(review.rating)}</Stack>
                <Text variant="bodySmall">{review.text}</Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      )
    }
  ];

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap align="start">
          <Box 
            background="var(--ggui-color-neutral-200, #e5e7eb)" 
            borderRadius={12} 
            padding={48} 
            style={{ flex: 1, minWidth: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Heading level={3}>{name}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{name}</Heading>
            <Text variant="bodyLarge">{currency} {price.toFixed(2)}</Text>
            <Stack direction="horizontal" align="center" gap={8}>
              <Stack direction="horizontal">{renderStars(rating)}</Stack>
              <Text variant="caption">({reviewCount} reviews)</Text>
            </Stack>
            <Box>
              <Badge variant={isLowStock ? "warning" : "success"}>
                {isOutOfStock ? "Out of Stock" : isLowStock ? "Low Stock" : "In Stock"}
              </Badge>
            </Box>
          </Stack>
        </Stack>

        <Divider />

        <Tabs items={tabItems} activeKey={activeTab} onChange={setActiveTab} />

        <Divider />

        <Stack direction="horizontal" gap={16} align="end">
          <Input 
            label="Quantity"
            type="number" 
            value={quantity.toString()} 
            onChange={(val) => setQuantity(Math.min(stock, Math.max(1, parseInt(val) || 1)))}
            disabled={isOutOfStock}
          />
          <Button 
            variant="primary" 
            onClick={() => onAddToCart({ productId: id, quantity })} 
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Heading, Input, Button, Badge, Box, Divider } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<Message>;
  /** Callback when sending a message */
  onSend: (message: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = "Chat",
    currentUser = "You",
    participantCount = 0,
    messages = [],
    onSend,
  } = props;

  const [inputValue, setInputValue] = useState('');
  const bottomRef = useRef<HTMLDivElement>(null);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    onSend({
      text: inputValue,
      timestamp: new Date().toISOString(),
    });
    setInputValue('');
  };

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  return (
    <Card shadow="md" padding={0} radius="lg" style={{ height: '600px', display: 'flex', flexDirection: 'column' }}>
      <Box paddingX={16} paddingY={16}>
        <Stack direction="horizontal" align="center" gap={8}>
          <Heading level={3}>{title}</Heading>
          {participantCount > 0 && <Badge variant="primary">{participantCount} Participants</Badge>}
        </Stack>
      </Box>
      <Divider margin={0} />
      <Box paddingX={16} paddingY={16} style={{ flex: 1, overflowY: 'auto' }}>
        <Stack gap={12}>
          {messages.map((msg, i) => {
            const isOwn = msg.sender === currentUser;
            const showSender = i === 0 || messages[i - 1].sender !== msg.sender;

            return (
              <Stack key={i} gap={2} style={{ alignSelf: isOwn ? 'flex-end' : 'flex-start', maxWidth: '80%' }}>
                {showSender && <Text variant="caption" align={isOwn ? 'right' : 'left'}>{msg.sender ?? 'Unknown'}</Text>}
                <Box 
                  paddingX={12} paddingY={8} 
                  borderRadius={8} 
                  background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-neutral-100)'}
                >
                  <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-neutral-900)'}>{msg.text}</Text>
                </Box>
                <Text variant="caption" align={isOwn ? 'right' : 'left'} color="var(--ggui-color-neutral-500)">
                  {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                </Text>
              </Stack>
            );
          })}
          <div ref={bottomRef} />
        </Stack>
      </Box>
      <Box padding={16} background="var(--ggui-color-neutral-50)">
        <Stack direction="horizontal" gap={8} align="end">
          <Box style={{ flex: 1 }}>
            <Input 
              label="Message"
              value={inputValue} 
              onChange={setInputValue} 
              placeholder="Type a message..."
              onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
            />
          </Box>
          <Button onClick={handleSend} disabled={!inputValue.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks?: Stock[];
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState<Stock[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);

  useEffect(() => {
    const handleData = (event: any) => {
      if (event.detail?.stocks) {
        setStocks(event.detail.stocks);
      }
      if (event.detail?.lastUpdated) {
        setLastUpdated(event.detail.lastUpdated);
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Box paddingY="var(--ggui-spacing-2, 8px)">
          <Heading level={1}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Last Updated: {new Date(lastUpdated).toLocaleString()}
            </Text>
          )}
        </Box>

        <Box 
          paddingY="var(--ggui-spacing-4, 16px)" 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
            gap: 'var(--ggui-spacing-4, 16px)' 
          }}
        >
          {stocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const color = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card 
                key={stock.symbol ?? index} 
                padding="var(--ggui-spacing-4, 16px)" 
                border={true}
                style={{
                  borderColor: isPositive ? 'var(--ggui-color-success-200, #bbf7d0)' : 'var(--ggui-color-error-200, #fecaca)'
                }}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={3}>{stock.symbol ?? '---'}</Heading>
                    <Text variant="overline" color={color}>
                      {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                    </Text>
                  </Stack>
                  <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                    {stock.name ?? 'Unknown Company'}
                  </Text>
                  <Divider margin="var(--ggui-spacing-2, 8px)" />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text size="2xl" weight="bold">
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>
                    <Text weight="semibold" color={color}>
                      {isPositive ? '+' : ''}{stock.change?.toFixed(2)}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {stocks.length === 0 && (
          <Box padding="var(--ggui-spacing-8, 32px)" style={{ textAlign: 'center' }}>
            <Text variant="body">Connecting to market data stream...</Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Checkbox, 
  Toggle, 
  Divider, 
  Spacer, 
  Container, 
  Box, 
  Progress 
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback triggered on final completion */
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions,
  roleOptions,
  onComplete
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0] ?? '',
    role: initialProfile.role ?? roleOptions[0] ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light'
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const updateField = (field: string, value: any) => 
    setFormData((prev) => ({ ...prev, [field]: value }));

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Stack direction="horizontal" justify="between" align="center">
          <Text variant="overline">Step {step} of 3</Text>
          <Text variant="caption" color="var(--ggui-color-neutral-500)">{((step / 3) * 100).toFixed(0)}% Complete</Text>
        </Stack>
        <Progress value={(step - 1) * 50} max={100} size="sm" />

        <Card padding={24} shadow="md">
          {step === 1 && (
            <Stack gap={16}>
              <Heading level={3}>Profile Setup</Heading>
              <Input 
                label="Name" 
                required 
                value={formData.name} 
                onChange={(v) => updateField('name', v)} 
              />
              <Input 
                label="Email" 
                type="email" 
                required 
                value={formData.email} 
                onChange={(v) => updateField('email', v)} 
                error={formData.email && !validateEmail(formData.email) ? 'Invalid email format' : undefined} 
              />
              <Text variant="label">Avatar</Text>
              <Stack direction="horizontal" gap={8}>
                {avatarOptions.map(emoji => (
                  <Button 
                    key={emoji} 
                    variant={formData.avatar === emoji ? 'primary' : 'outline'} 
                    size="sm" 
                    onClick={() => updateField('avatar', emoji)}
                  >
                    {emoji}
                  </Button>
                ))}
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={3}>Preferences</Heading>
              <Select 
                label="Role" 
                value={formData.role} 
                onChange={(v) => updateField('role', v)} 
                options={roleOptions.map(r => ({ value: r, label: r }))} 
              />
              <Divider margin={8} />
              <Checkbox 
                label="Email Notifications" 
                checked={formData.emailNotifications} 
                onChange={(v) => updateField('emailNotifications', v)} 
              />
              <Toggle 
                label={`Theme: ${formData.theme === 'light' ? 'Light' : 'Dark'}`} 
                checked={formData.theme === 'dark'} 
                onChange={(v) => updateField('theme', v ? 'dark' : 'light')} 
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={3}>Review & Confirm</Heading>
              <Box padding={16} background="var(--ggui-color-neutral-100)" borderRadius={8}>
                <Stack gap={8}>
                  <Text variant="bodySmall"><strong>Name:</strong> {formData.name}</Text>
                  <Text variant="bodySmall"><strong>Email:</strong> {formData.email}</Text>
                  <Text variant="bodySmall"><strong>Avatar:</strong> {formData.avatar}</Text>
                  <Text variant="bodySmall"><strong>Role:</strong> {formData.role}</Text>
                  <Text variant="bodySmall"><strong>Notifications:</strong> {formData.emailNotifications ? 'On' : 'Off'}</Text>
                  <Text variant="bodySmall"><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Box>
            </Stack>
          )}

          <Spacer size={24} />
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={handleBack}>Go Back</Button>
            {step < 3 ? (
              <Button variant="primary" disabled={step === 1 && !isStep1Valid} onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete?.(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
